const TOLERANCE = 0.01;
const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  const internal = parseFloat(d.internal_balance ?? 'NaN');
  const custodian = parseFloat(d.custodian_balance ?? 'NaN');
  const difference = parseFloat((internal - custodian).toFixed(6));
  const absDiff = Math.abs(difference);
  const mismatch = isNaN(internal) || isNaN(custodian) || absDiff > TOLERANCE;

  results.push({
    json: {
      account_id: d.account_id,
      currency: d.currency,
      internal_balance: internal,
      custodian_balance: custodian,
      difference: difference,
      abs_difference: absDiff,
      mismatch: mismatch,
      checked_at: new Date().toISOString()
    }
  });
}

return results;

